      no() {
        this.count++;
        switch (this.count) {
          case 1:
            this.$Message.info("小姐姐在考虑一下呗");
            break;
          case 2:
            this.$Message.info("你是我见过的最漂亮善良可爱的女孩子");
            break;
          case 3:
            this.$Message.info("一生一世爱你");
            break;
          case 4:
            this.$Message.info("家务我全干");
            break;
          case 5:
            this.$Message.info("不藏私房钱");
            break;
          case 6:
            this.$Message.info("房子写你名");
            break;
          case 7:
            this.$Message.info("工资全上交");
            this.count = 1;
            break;
          default:
            this.$Message.info("小姐姐在考虑一下呗");
        }
      },
    }

  }

</script>


